// Query building example
async function searchUsers(queryParams) {
  const { 
    name, 
    role, 
    minAge, 
    maxAge, 
    isActive,
    page = 1,
    limit = 10,
    sortBy = 'createdAt',
    sortOrder = 'desc'
  } = queryParams;

  // Build query
  let query = User.find();

  // Apply filters
  if (name) {
    query = query.where('name').regex(new RegExp(name, 'i'));
  }
  if (role) {
    query = query.where('role').equals(role);
  }
  if (minAge) {
    query = query.where('age').gte(parseInt(minAge));
  }
  if (maxAge) {
    query = query.where('age').lte(parseInt(maxAge));
  }
  if (isActive !== undefined) {
    query = query.where('isActive').equals(isActive === 'true');
  }

  // Pagination
  const skip = (page - 1) * limit;
  query = query.skip(skip).limit(parseInt(limit));

  // Sorting
  const sort = {};
  sort[sortBy] = sortOrder === 'desc' ? -1 : 1;
  query = query.sort(sort);

  // Execute query
  const users = await query.exec();

  // Get total count for pagination
  const total = await User.countDocuments(query.getFilter());

  return {
    users,
    pagination: {
      total,
      page: parseInt(page),
      limit: parseInt(limit),
      pages: Math.ceil(total / limit)
    }
  };
}

// Using populate for relationships
async function getUserWithPosts(userId) {
  return await User.findById(userId)
    .populate('posts')  // Assuming User has posts reference
    .select('-__v');
}

// Custom validation
const userSchema = new mongoose.Schema({
  email: {
    type: String,
    required: true,
    validate: {
      validator: function(v) {
        return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(v);
      },
      message: props => `${props.value} is not a valid email!`
    }
  },
  password: {
    type: String,
    required: true,
    minlength: 8
  },
  confirmPassword: {
    type: String,
    required: true,
    validate: {
      validator: function(v) {
        return this.password === v;
      },
      message: 'Passwords do not match!'
    }
  }
});

// Error handling in operations
try {
  const user = new User({
    name: '',  // Will fail validation
    email: 'invalid-email'
  });
  await user.save();
} catch (error) {
  // Handle different error types
  if (error.name === 'ValidationError') {
    // Validation errors
    const messages = Object.values(error.errors).map(err => err.message);
    console.error('Validation errors:', messages);
  } else if (error.code === 11000) {
    // Duplicate key error
    console.error('Duplicate entry:', error.keyValue);
  } else {
    // Other errors
    console.error('Error:', error.message);
  }
}

// Custom error class
class AppError extends Error {
  constructor(message, statusCode) {
    super(message);
    this.statusCode = statusCode;
    this.isOperational = true;
    Error.captureStackTrace(this, this.constructor);
  }
}
